            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes defined via EF.
            // EF 9 now throws instead of silently ignoring. Remove HasIndex and use
            // the Azure portal to manage Cosmos indexing policies.
            entity.HasNoKey(); // indexes are removed below
        });

        // Actually: keep the key, just remove the index.  Rewrite properly:
    }
}
