     public DbSet<Blog> Blogs => Set<Blog>();

     protected override void OnModelCreating(ModelBuilder modelBuilder)
     {
         modelBuilder.Entity<Blog>(entity =>
         {
             // BREAKING CHANGE 1 – Discriminator property renamed "$type" in EF 9.
             // Existing documents use "Discriminator", so keep the old JSON name.
             entity.HasDiscriminator<string>("Discriminator");

             // BREAKING CHANGE 2 – HasIndex() now throws for Cosmos provider.
             // Remove the call; manage indexing policy via the Azure portal.
             // (was: entity.HasIndex(b => b.Name))
         });
     }

     protected override void OnConfiguring(DbContextOptionsBuilder options)
     {
         base.OnConfiguring(options);

         // BREAKING CHANGE 3 – Sync I/O now throws by default in EF 9 Cosmos.
         // Either switch to async APIs (preferred) or opt back in:
         // options.UseCosmos(..., cosmosOptions => cosmosOptions.AllowSynchronousIO());
     }
 }

 class Blog
 {
     public string Id { get; set; }
     public string Name { get; set; }
 }

